CREATE TABLE IF NOT EXISTS sys_department (
  id BIGINT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(128) NOT NULL, parent_id BIGINT DEFAULT 0,
  sort_order INT DEFAULT 0, status VARCHAR(32) DEFAULT 'ENABLED',
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0
);
CREATE TABLE IF NOT EXISTS sys_user (
  id BIGINT PRIMARY KEY AUTO_INCREMENT, username VARCHAR(64) NOT NULL UNIQUE, display_name VARCHAR(128) NOT NULL,
  password VARCHAR(255) NOT NULL, email VARCHAR(128) NOT NULL, status VARCHAR(32) NOT NULL, department_id BIGINT,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0
);
CREATE TABLE IF NOT EXISTS sys_role (
  id BIGINT PRIMARY KEY AUTO_INCREMENT, role_code VARCHAR(64) NOT NULL UNIQUE, role_name VARCHAR(128) NOT NULL, status VARCHAR(32) NOT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0
);
CREATE TABLE IF NOT EXISTS sys_menu (
  id BIGINT PRIMARY KEY AUTO_INCREMENT, parent_id BIGINT DEFAULT 0, menu_name VARCHAR(128) NOT NULL, menu_path VARCHAR(255) NOT NULL, sort_order INT NOT NULL DEFAULT 0,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0
);
CREATE TABLE IF NOT EXISTS sys_permission (
  id BIGINT PRIMARY KEY AUTO_INCREMENT, permission_code VARCHAR(128) NOT NULL UNIQUE, permission_name VARCHAR(128) NOT NULL, module VARCHAR(64) NOT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0
);
CREATE TABLE IF NOT EXISTS sys_user_role (
  id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT NOT NULL, role_id BIGINT NOT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0
);
CREATE TABLE IF NOT EXISTS sys_role_menu (
  id BIGINT PRIMARY KEY AUTO_INCREMENT, role_id BIGINT NOT NULL, menu_id BIGINT NOT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0
);
CREATE TABLE IF NOT EXISTS sys_role_permission (
  id BIGINT PRIMARY KEY AUTO_INCREMENT, role_id BIGINT NOT NULL, permission_id BIGINT NOT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0
);
CREATE TABLE IF NOT EXISTS sys_data_scope_policy (
  id BIGINT PRIMARY KEY AUTO_INCREMENT, policy_name VARCHAR(128) NOT NULL, scope_type VARCHAR(64) NOT NULL, role_id BIGINT,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0
);
CREATE TABLE IF NOT EXISTS sys_login_log (
  id BIGINT PRIMARY KEY AUTO_INCREMENT, username VARCHAR(64) NOT NULL, ip_address VARCHAR(64) NOT NULL, result_status VARCHAR(32) NOT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0
);
CREATE TABLE IF NOT EXISTS cms_column (id BIGINT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(128) NOT NULL, parent_id BIGINT DEFAULT 0, status VARCHAR(32) DEFAULT 'ENABLED', sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS cms_page (id BIGINT PRIMARY KEY AUTO_INCREMENT, page_key VARCHAR(128) NOT NULL, page_name VARCHAR(128) NOT NULL, config_json JSON, status VARCHAR(32) DEFAULT 'ENABLED', sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS cms_article (id BIGINT PRIMARY KEY AUTO_INCREMENT, title VARCHAR(255) NOT NULL, content LONGTEXT, column_id BIGINT NOT NULL, status VARCHAR(32) NOT NULL, sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS cms_article_version (id BIGINT PRIMARY KEY AUTO_INCREMENT, article_id BIGINT NOT NULL, version_no INT NOT NULL, snapshot LONGTEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS cms_country (id BIGINT PRIMARY KEY AUTO_INCREMENT, country_code VARCHAR(32), country_name VARCHAR(128), status VARCHAR(32) DEFAULT 'ENABLED', sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS cms_school (id BIGINT PRIMARY KEY AUTO_INCREMENT, school_name VARCHAR(255), country_id BIGINT, status VARCHAR(32) DEFAULT 'ENABLED', sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS cms_case (id BIGINT PRIMARY KEY AUTO_INCREMENT, title VARCHAR(255), country_id BIGINT, status VARCHAR(32) DEFAULT 'ENABLED', sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS cms_seo_config (id BIGINT PRIMARY KEY AUTO_INCREMENT, seo_key VARCHAR(128), title VARCHAR(255), keywords VARCHAR(512), description VARCHAR(1024), status VARCHAR(32) DEFAULT 'ENABLED', sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS media_asset (id BIGINT PRIMARY KEY AUTO_INCREMENT, file_name VARCHAR(255), file_url VARCHAR(512), category_id BIGINT, status VARCHAR(32) DEFAULT 'ENABLED', sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS media_category (id BIGINT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(128), status VARCHAR(32) DEFAULT 'ENABLED', sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS media_tag (id BIGINT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(128), status VARCHAR(32) DEFAULT 'ENABLED', sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS media_asset_tag_rel (id BIGINT PRIMARY KEY AUTO_INCREMENT, asset_id BIGINT, tag_id BIGINT, status VARCHAR(32) DEFAULT 'ENABLED', sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS lead_record (id BIGINT PRIMARY KEY AUTO_INCREMENT, student_name VARCHAR(128) NOT NULL, phone VARCHAR(32) NOT NULL, status VARCHAR(32) NOT NULL, assigned_to BIGINT, sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS lead_follow_record (id BIGINT PRIMARY KEY AUTO_INCREMENT, lead_id BIGINT NOT NULL, follow_content VARCHAR(2000) NOT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS lead_assign_record (id BIGINT PRIMARY KEY AUTO_INCREMENT, lead_id BIGINT NOT NULL, from_user BIGINT, to_user BIGINT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS lead_source_rule (id BIGINT PRIMARY KEY AUTO_INCREMENT, rule_name VARCHAR(128), source_key VARCHAR(128), status VARCHAR(32) DEFAULT 'ENABLED', sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS site_config (id BIGINT PRIMARY KEY AUTO_INCREMENT, site_name VARCHAR(128), logo_url VARCHAR(512), favicon_url VARCHAR(512), status VARCHAR(32) DEFAULT 'ENABLED', sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS site_navigation (id BIGINT PRIMARY KEY AUTO_INCREMENT, nav_name VARCHAR(128), nav_link VARCHAR(512), status VARCHAR(32) DEFAULT 'ENABLED', sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS site_footer_config (id BIGINT PRIMARY KEY AUTO_INCREMENT, footer_json JSON, status VARCHAR(32) DEFAULT 'ENABLED', sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS sys_dictionary (id BIGINT PRIMARY KEY AUTO_INCREMENT, dict_type VARCHAR(128), dict_key VARCHAR(128), dict_value VARCHAR(255), status VARCHAR(32) DEFAULT 'ENABLED', sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS sys_config_item (id BIGINT PRIMARY KEY AUTO_INCREMENT, config_key VARCHAR(128) UNIQUE, config_value VARCHAR(1024), description VARCHAR(255), status VARCHAR(32) DEFAULT 'ENABLED', sort_order INT DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS sys_operation_log (id BIGINT PRIMARY KEY AUTO_INCREMENT, operator VARCHAR(128) NOT NULL, module VARCHAR(64) NOT NULL, action VARCHAR(128) NOT NULL, request_path VARCHAR(255) NOT NULL, request_time DATETIME NOT NULL, result_status VARCHAR(32) NOT NULL, risk_tag VARCHAR(64) NOT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS sys_publish_log (id BIGINT PRIMARY KEY AUTO_INCREMENT, module VARCHAR(64), biz_id BIGINT, publish_status VARCHAR(32), summary VARCHAR(1024), created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS sys_security_audit_log (id BIGINT PRIMARY KEY AUTO_INCREMENT, event_type VARCHAR(128), username VARCHAR(128), ip_address VARCHAR(64), detail VARCHAR(1024), risk_tag VARCHAR(64), created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, created_by BIGINT NOT NULL DEFAULT 0, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, updated_by BIGINT NOT NULL DEFAULT 0, deleted_flag TINYINT(1) NOT NULL DEFAULT 0);

